import React from 'react';

const Home = () => {
  const services = [
    { name: 'Cargo Flight', img: '/butans/cargo-flay.jpg' },
    { name: 'Ship Cargo', img: '/butans/ship-cargo.jpg' },
    { name: 'Home Shifting', img: '/butans/home-shifting.jpg' },
    { name: 'Parcel Delivery', img: '/butans/parcel-delivry.jpg' }
  ];

  return (
    <div style={{ padding: '20px', fontFamily: 'Arial' }}>
      <h1>Logistics & Transport</h1>
      <div style={{ 
        display: 'grid', 
        gridTemplateColumns: '1fr 1fr', 
        gap: '15px' 
      }}>
        {services.map((item, index) => (
          <div key={index} style={{ 
            border: '2px solid #000', 
            padding: '10px', 
            textAlign: 'center',
            borderRadius: '5px' 
          }}>
            <img src={item.img} alt={item.name} style={{ width: '100%', height: 'auto' }} />
            <p style={{ fontWeight: 'bold' }}>{item.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
};
export default Home;
